import{_ as e,o as a,c as s,a2 as r}from"./chunks/framework.DTa47_fH.js";const u=JSON.parse('{"title":"LLM Assessment","description":"","frontmatter":{},"headers":[],"relativePath":"assessment/llm.md","filePath":"assessment/llm.md"}'),n={name:"assessment/llm.md"};function o(i,t,d,l,c,m){return a(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="llm-assessment" tabindex="-1">LLM Assessment <a class="header-anchor" href="#llm-assessment" aria-label="Permalink to &quot;LLM Assessment&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Coming soon</p><p>LLM Assessment is on the roadmap (milestone #0045). The description below reflects the planned capability based on the current design specification.</p></div><p>LLM Assessment evaluates large language models as the subject of a sovereignty assessment, rather than using them as analysis tools. It connects to multiple LLM providers simultaneously and benchmarks each against the <code>SWAO_LLM_ASSESS</code> community framework, producing a side-by-side comparison to support model selection decisions for sovereign workloads.</p><p><strong>Planned CLI:</strong> <code>swao assess --type llm</code></p><p><strong>TUI:</strong> Main Menu &gt; Run Assessment &gt; [4] LLM Assessment (coming soon)</p><hr><h2 id="why-it-matters" tabindex="-1">Why it matters <a class="header-anchor" href="#why-it-matters" aria-label="Permalink to &quot;Why it matters&quot;">​</a></h2><p>Before deploying any AI application to a sovereign environment, organisations must evaluate whether their chosen LLM meets the jurisdiction&#39;s requirements for data residency, transparency, safety, and regulatory compliance. Today this relies on vendor claims and informal testing. LLM Assessment makes it structured, repeatable, and auditor-defensible.</p><hr><h2 id="what-it-assesses" tabindex="-1">What it assesses <a class="header-anchor" href="#what-it-assesses" aria-label="Permalink to &quot;What it assesses&quot;">​</a></h2><p>The <code>SWAO_LLM_ASSESS</code> framework covers seven domains:</p><table tabindex="0"><thead><tr><th>Domain</th><th>What it evaluates</th></tr></thead><tbody><tr><td>Data sovereignty and residency</td><td>Contractual data residency guarantees, zero-retention endpoints, EU hosting options, GDPR DPA compliance</td></tr><tr><td>Model transparency</td><td>Published model card, EU AI Act conformity assessment, per-call audit metadata, licensing terms</td></tr><tr><td>Performance and reliability</td><td>Latency, hallucination rate, context window, token throughput, cost</td></tr><tr><td>Cultural and language fit</td><td>Target-language fluency, domain vocabulary accuracy, regulatory body awareness</td></tr><tr><td>Safety and bias</td><td>BOLD/WinoBias benchmarks, red-team disclosure, EU AI Act prohibited-use test, prompt injection resistance, jailbreak resilience</td></tr><tr><td>Agentic capabilities</td><td>Tool calling reliability, multi-step orchestration, RAG grounding fidelity, memory coherence, structured output compliance</td></tr><tr><td>People and team readiness</td><td>LLM engineering skills, data management, AI governance roles, continuous learning commitment</td></tr></tbody></table><hr><h2 id="what-it-produces" tabindex="-1">What it produces <a class="header-anchor" href="#what-it-produces" aria-label="Permalink to &quot;What it produces&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Output</th><th>What it contains</th></tr></thead><tbody><tr><td>Sovereignty Readiness Score (SRS)</td><td>A 0-100 score per model, weighted by domain</td></tr><tr><td>Side-by-side comparison table</td><td>Each framework control with RAG status (pass/partial/fail) for every assessed model</td></tr><tr><td>Regulatory fit summary</td><td>Which GDPR-linked controls pass for each model</td></tr><tr><td>Benchmark report</td><td>Latency, throughput, cost estimates, and grounding test results</td></tr></tbody></table><hr><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>LLM Assessment is configured in <code>.swao.yml</code> under the <code>llm_assessment:</code> block, where you specify which models to assess, thresholds, target locale, and budget ceiling. API keys are read from environment variables -- never stored in the configuration file.</p>',18)])])}const p=e(n,[["render",o]]);export{u as __pageData,p as default};
